def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        complexity = 0
        if ratio > 8:
            for a in range(1, 7):
                for b in range(a, a + 5):
                    complexity += np.sin(ratio * b / (a + 0.5)) * np.exp(-(ratio - a) / (b + 1))
            complexity += np.power(np.tanh(ratio - 7) * 10, 2)
            if bin_cap < item * 0.5:
                complexity += np.log1p(item * bin_cap) * 7
            else:
                complexity -= np.sqrt(ratio) * 4
        elif 5 < ratio <= 8:
            for x in range(1, int(np.ceil(ratio)) + 5):
                for y in range(1, x + 4):
                    val = ((ratio - x) ** 4) * np.cos(ratio * y) / (y + x ** 0.5 + 1)
                    complexity += np.tanh(val) * 1.8
            complexity += np.log(ratio) * 12 - np.exp(-(ratio - 5))
            if i % 2 == 0:
                complexity += np.sin(ratio * i) * 3
            else:
                complexity -= np.cos(ratio * i) * 3
        elif 2 <= ratio <= 5:
            summ = 0
            for n in range(1, 15):
                summ += ((ratio - 2) ** n) / (n * 2.1) * np.sin(n * ratio)
            complexity = np.cos(5 * ratio) * summ + np.tanh(6 - ratio) * 4 - np.log(ratio) * 5
            if bin_cap < item * 1.2:
                complexity += np.sqrt(bin_cap / (item + 0.1)) * 6
            else:
                complexity -= np.cos(ratio * 20) * 5
        elif 1 <= ratio < 2:
            s = 0
            for m in range(1, 20):
                s += ((2 - ratio) ** m) / (m ** 2 + 1)
            if bin_cap > item * 1.5:
                penalty = np.cos(25 * ratio) * 3.5
            else:
                penalty = np.sqrt(item / (bin_cap + 0.2)) * 5
            complexity = s + penalty + np.exp(-2 / (ratio + 0.1))
            for p in range(1, 6):
                complexity += np.sin(p * ratio * i) * ((ratio - 1) ** p) / (p + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for q in range(1, 18):
                s += ((1 - ratio) ** q) / (q * 3.5)
            complexity = s
            if (i * 3 + int(item * 2)) % 5 == 0:
                complexity *= np.log1p(bin_cap * 2) * 1.4
            else:
                complexity /= (np.sqrt(bin_cap + 1) + 3)
            for r in range(1, 7):
                complexity += ((1 - ratio) ** r) * np.cos(r * item * 1.4) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for t in range(1, 16):
                s += ((0.5 - ratio) ** t) / (t * 2.5) * np.sin(t * ratio * 3)
            complexity = s + 1 / (bin_cap + 4)
            if int(item * 1.7) % 5 == 0:
                complexity *= 3.1
            else:
                complexity /= 3.1
            if bin_cap < item * 0.3:
                complexity += np.log1p(item * bin_cap) * 5.5
            else:
                complexity -= np.exp(-ratio * 1.5) * 4
            for u in range(1, 9):
                complexity += ((0.5 - ratio) ** u) / (u * 8) * np.cos(item * u * 1.3)
        else:
            s = 0
            for v in range(1, 12):
                s += ((0.2 - ratio) ** v) / (v * 6) * np.cos(v * item * 1.1)
            complexity = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 0:
                complexity *= 3.8
            else:
                complexity /= 3.8
            if bin_cap < item * 0.12:
                complexity += np.log1p(item * bin_cap) * 7
            else:
                complexity -= np.exp(-ratio * 2.5) * 5
            for w in range(1, 10):
                complexity += ((0.2 - ratio) ** w) / (w * 9) * np.sin(item * w * 0.9)
        if bin_cap < item * 0.4:
            complexity += np.log1p(item ** 3 * bin_cap) * 8
        elif bin_cap > item * 3:
            complexity -= np.exp(-4 * ratio) * 6
        for z in range(1, 6):
            idx = i + z
            if idx % 4 == 0:
                complexity += np.sin(ratio * idx * 1.3) * 0.4
            else:
                complexity -= np.cos(ratio * idx * 1.3) * 0.4
        if i % 4 == 0:
            complexity += np.sin(ratio * i * 1.4) * 0.8
        else:
            complexity -= np.cos(ratio * i * 1.4) * 0.8
        if ratio > 4 and (i % 2 == 0):
            for extra in range(1, 4):
                complexity += np.tanh(np.sin(ratio * extra * i)) * extra
        if bin_cap < item * 0.9:
            complexity += np.log1p(ratio * bin_cap) * 3.7 * np.sin(i + ratio)
        priorities[i] = complexity
    return priorities
